create extension if not exists "pgcrypto";
create table if not exists public.profiles (id uuid primary key references auth.users(id) on delete cascade,email text,full_name text,avatar_url text,main_role text not null default 'passenger' check (main_role in ('passenger','driver','station_owner','company','admin')),phone text,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.companies (id uuid primary key default gen_random_uuid(),name text not null,siret text,contact_email text,created_by uuid references public.profiles(id) on delete set null,created_at timestamptz not null default now());
create table if not exists public.company_users (id uuid primary key default gen_random_uuid(),company_id uuid not null references public.companies(id) on delete cascade,user_id uuid not null references public.profiles(id) on delete cascade,role text not null default 'member' check (role in ('owner','admin','member')),created_at timestamptz not null default now(),unique(company_id,user_id));
create table if not exists public.rides (id uuid primary key default gen_random_uuid(),driver_id uuid not null references public.profiles(id) on delete cascade,origin text not null,destination text not null,departure_time timestamptz not null,seats_total integer not null default 1 check(seats_total>=1),seats_available integer not null default 1 check(seats_available>=0),price_cents integer check(price_cents is null or price_cents>=0),vehicle_info text,status text not null default 'active' check(status in ('active','cancelled','completed')),created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.ride_bookings (id uuid primary key default gen_random_uuid(),ride_id uuid not null references public.rides(id) on delete cascade,passenger_id uuid not null references public.profiles(id) on delete cascade,seats_booked integer not null default 1 check(seats_booked>=1),status text not null default 'confirmed' check(status in ('pending','confirmed','cancelled')),created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(ride_id,passenger_id));
create table if not exists public.charging_stations (id uuid primary key default gen_random_uuid(),owner_id uuid not null references public.profiles(id) on delete cascade,name text not null,address text not null,city text,power_kw numeric,plug_type text,price_cents_per_kwh integer check(price_cents_per_kwh is null or price_cents_per_kwh>=0),status text not null default 'available' check(status in ('available','occupied','out_of_service')),description text,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.charging_bookings (id uuid primary key default gen_random_uuid(),station_id uuid not null references public.charging_stations(id) on delete cascade,user_id uuid not null references public.profiles(id) on delete cascade,starts_at timestamptz not null,ends_at timestamptz not null,status text not null default 'confirmed' check(status in ('pending','confirmed','cancelled','completed')),created_at timestamptz not null default now());
create table if not exists public.station_reports (id uuid primary key default gen_random_uuid(),station_id uuid not null references public.charging_stations(id) on delete cascade,reporter_id uuid not null references public.profiles(id) on delete cascade,reason text not null,details text,created_at timestamptz not null default now());
create table if not exists public.company_requests (id uuid primary key default gen_random_uuid(),name text not null,email text not null,company_name text,message text,status text not null default 'new' check(status in ('new','contacted','qualified','closed')),created_at timestamptz not null default now());
create table if not exists public.contact_messages (id uuid primary key default gen_random_uuid(),nom text not null,email text not null,entreprise text,message text not null,created_at timestamptz not null default now());
alter table public.profiles enable row level security; alter table public.companies enable row level security; alter table public.company_users enable row level security; alter table public.rides enable row level security; alter table public.ride_bookings enable row level security; alter table public.charging_stations enable row level security; alter table public.charging_bookings enable row level security; alter table public.station_reports enable row level security; alter table public.company_requests enable row level security; alter table public.contact_messages enable row level security;
drop policy if exists profiles_select_own on public.profiles; create policy profiles_select_own on public.profiles for select to authenticated using(auth.uid()=id);
drop policy if exists profiles_insert_own on public.profiles; create policy profiles_insert_own on public.profiles for insert to authenticated with check(auth.uid()=id);
drop policy if exists profiles_update_own on public.profiles; create policy profiles_update_own on public.profiles for update to authenticated using(auth.uid()=id) with check(auth.uid()=id);
drop policy if exists rides_select_active_or_own on public.rides; create policy rides_select_active_or_own on public.rides for select to authenticated using(status='active' or driver_id=auth.uid());
drop policy if exists rides_insert_own on public.rides; create policy rides_insert_own on public.rides for insert to authenticated with check(driver_id=auth.uid());
drop policy if exists rides_update_own on public.rides; create policy rides_update_own on public.rides for update to authenticated using(driver_id=auth.uid()) with check(driver_id=auth.uid());
drop policy if exists ride_bookings_select_own on public.ride_bookings; create policy ride_bookings_select_own on public.ride_bookings for select to authenticated using(passenger_id=auth.uid() or exists(select 1 from public.rides r where r.id=ride_bookings.ride_id and r.driver_id=auth.uid()));
drop policy if exists ride_bookings_insert_own on public.ride_bookings; create policy ride_bookings_insert_own on public.ride_bookings for insert to authenticated with check(passenger_id=auth.uid());
drop policy if exists charging_stations_select_all on public.charging_stations; create policy charging_stations_select_all on public.charging_stations for select to authenticated using(true);
drop policy if exists charging_stations_insert_own on public.charging_stations; create policy charging_stations_insert_own on public.charging_stations for insert to authenticated with check(owner_id=auth.uid());
drop policy if exists charging_stations_update_own on public.charging_stations; create policy charging_stations_update_own on public.charging_stations for update to authenticated using(owner_id=auth.uid()) with check(owner_id=auth.uid());
drop policy if exists charging_bookings_select_own on public.charging_bookings; create policy charging_bookings_select_own on public.charging_bookings for select to authenticated using(user_id=auth.uid() or exists(select 1 from public.charging_stations s where s.id=charging_bookings.station_id and s.owner_id=auth.uid()));
drop policy if exists charging_bookings_insert_own on public.charging_bookings; create policy charging_bookings_insert_own on public.charging_bookings for insert to authenticated with check(user_id=auth.uid());
drop policy if exists station_reports_insert_own on public.station_reports; create policy station_reports_insert_own on public.station_reports for insert to authenticated with check(reporter_id=auth.uid());
drop policy if exists station_reports_select_own_or_station_owner on public.station_reports; create policy station_reports_select_own_or_station_owner on public.station_reports for select to authenticated using(reporter_id=auth.uid() or exists(select 1 from public.charging_stations s where s.id=station_reports.station_id and s.owner_id=auth.uid()));
drop policy if exists companies_select_members on public.companies; create policy companies_select_members on public.companies for select to authenticated using(created_by=auth.uid() or exists(select 1 from public.company_users cu where cu.company_id=companies.id and cu.user_id=auth.uid()));
drop policy if exists companies_insert_own on public.companies; create policy companies_insert_own on public.companies for insert to authenticated with check(created_by=auth.uid());
drop policy if exists company_users_select_own on public.company_users; create policy company_users_select_own on public.company_users for select to authenticated using(user_id=auth.uid());
drop policy if exists company_requests_insert_authenticated on public.company_requests; create policy company_requests_insert_authenticated on public.company_requests for insert to authenticated with check(true);
create or replace function public.handle_new_user() returns trigger language plpgsql security definer set search_path=public as $$ begin insert into public.profiles(id,email,full_name,avatar_url) values(new.id,new.email,coalesce(new.raw_user_meta_data->>'full_name',new.email),new.raw_user_meta_data->>'avatar_url') on conflict(id) do nothing; return new; end; $$;
drop trigger if exists on_auth_user_created on auth.users; create trigger on_auth_user_created after insert on auth.users for each row execute function public.handle_new_user();
create or replace function public.book_ride(p_ride_id uuid,p_passenger_id uuid) returns uuid language plpgsql security definer set search_path=public as $$ declare v_driver_id uuid; v_seats_available integer; v_booking_id uuid; begin if p_passenger_id is distinct from auth.uid() then raise exception 'Action non autorisée.'; end if; select driver_id,seats_available into v_driver_id,v_seats_available from public.rides where id=p_ride_id and status='active' for update; if v_driver_id is null then raise exception 'Trajet introuvable ou inactif.'; end if; if v_driver_id=p_passenger_id then raise exception 'Vous ne pouvez pas réserver votre propre trajet.'; end if; if v_seats_available<1 then raise exception 'Plus aucune place disponible.'; end if; insert into public.ride_bookings(ride_id,passenger_id,seats_booked,status) values(p_ride_id,p_passenger_id,1,'confirmed') returning id into v_booking_id; update public.rides set seats_available=seats_available-1,updated_at=now() where id=p_ride_id; return v_booking_id; exception when unique_violation then raise exception 'Vous avez déjà réservé ce trajet.'; end; $$;
